14	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => alive.has(cellKey([x + dx, y + dy]))).length;
15	
16	  const candidates = new Map<string, Cell>();
17	  for (const [x, y] of cells) {
18	    candidates.set(cellKey([x, y]), [x, y]);
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const nx = x + dx;
21	      const ny = y + dy;
22	      candidates.set(cellKey([nx, ny]), [nx, ny]);
23	    }
24	  }
25	
26	  const isAliveNext = (cell: Cell): boolean => {
27	    const liveNeighbors = liveNeighborCount(cell);
28	    if (alive.has(cellKey(cell))) {
29	      return liveNeighbors === 2 || liveNeighbors === 3;
30	    }
31	    return liveNeighbors === 3;
