export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(cellKey));
  const liveNeighborCount = ([x, y]: Cell): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => alive.has(cellKey([x + dx, y + dy]))).length;

  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    candidates.set(cellKey([x, y]), [x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      candidates.set(cellKey([nx, ny]), [nx, ny]);
    }
  }

  const isAliveNext = (cell: Cell): boolean => {
    const liveNeighbors = liveNeighborCount(cell);
    if (alive.has(cellKey(cell))) {
      return liveNeighbors === 2 || liveNeighbors === 3;
    }
    return liveNeighbors === 3;
  };

  return [...candidates.values()].filter(isAliveNext);
}

