export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(cellKey));
  const neighborsOf = ([x, y]: Cell): Cell[] =>
    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
  const liveNeighborCount = (cell: Cell): number =>
    neighborsOf(cell).filter((n) => alive.has(cellKey(n))).length;

  const candidates = new Map<string, Cell>(
    cells.flatMap((cell) => [cell, ...neighborsOf(cell)]).map((c) => [cellKey(c), c])
  );

  const isAliveNext = (cell: Cell): boolean => {
    const n = liveNeighborCount(cell);
    return alive.has(cellKey(cell)) ? n === 2 || n === 3 : n === 3;
  };

  return [...candidates.values()].filter(isAliveNext);
}

